async (params, browser) => {
  // Open Google Sheets home
  await browser.open('https://docs.google.com/spreadsheets/')

  // Wait for search input to appear
  await browser.waitForSelector('input[aria-label=\'Search\'], input[type=\'search\'], [role=\'search\'] input', 15000)

  // Let the page fully load
  await browser.wait(2000)

  // Click search input
  await browser.click('input[aria-label=\'Search\'], input[type=\'search\'], [role=\'search\'] input')

  // Brief pause
  await browser.wait(500)

  // Type query and press Enter
  const search_trigger = await browser.evaluate(`const searchInput = document.querySelector('input[aria-label="Search"], input[type="search"], [role="search"] input'); if (!searchInput) return { error: 'Could not find search input' }; searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); searchInput.select(); document.execCommand('insertText', false, params.query); await new Promise(r => setTimeout(r, 500)); searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); return { searched: true }`)

  // Wait for search results to load
  await browser.wait(4000)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[data-id], .docs-homescreen-list-item, [role="listitem"], .goog-list-item, a[data-document-id]'); if (items.length === 0) { const links = document.querySelectorAll('a[href*="/spreadsheets/d/"]'); const seen = new Set(); links.forEach(link => { if (results.length >= 15) return; const href = link.href; if (seen.has(href)) return; seen.add(href); const container = link.closest('[role="listitem"], [data-id], tr, li, div'); const nameEl = container ? container.querySelector('[data-column="name"], .docs-homescreen-item-name, .doc-title') : null; const dateEl = container ? container.querySelector('[data-column="date"], .docs-homescreen-item-date, time') : null; results.push({ name: nameEl ? nameEl.textContent.trim() : link.textContent.trim() || 'Untitled', url: href, last_opened: dateEl ? dateEl.textContent.trim() : '' }); }); } else { const seen = new Set(); items.forEach(item => { if (results.length >= 15) return; const link = item.querySelector('a[href*="/spreadsheets/d/"]') || (item.tagName === 'A' && item.href && item.href.includes('/spreadsheets/d/') ? item : null); if (!link) return; const href = link.href; if (seen.has(href)) return; seen.add(href); const nameEl = item.querySelector('[data-column="name"], .docs-homescreen-item-name, .doc-title, [aria-label]'); const dateEl = item.querySelector('[data-column="date"], .docs-homescreen-item-date, time, .docs-homescreen-item-owner-date'); results.push({ name: nameEl ? (nameEl.getAttribute('aria-label') || nameEl.textContent || '').trim() : link.textContent.trim() || 'Untitled', url: href, last_opened: dateEl ? dateEl.textContent.trim() : '' }); }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
